from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Convert a list of triples about a politician into a readable sentence."""
    if not triples:
        return ""

    # Identify the main subject (most common subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Group triples by predicate type
    predicates = {}
    for t in triples:
        if t.predicate not in predicates:
            predicates[t.predicate] = []
        predicates[t.predicate].append(t.object)

    # Build sentence parts based on predicate categories
    parts = []

    # Personal information (birth, death, nationality)
    birth_info = []
    if "birthPlace" in predicates:
        birth_info.append(f"born in {predicates['birthPlace'][0]}")
    if "birthDate" in predicates:
        birth_info.append(f"on {predicates['birthDate'][0]}")
    if "birthYear" in predicates:
        birth_info.append(f"in {predicates['birthYear'][0]}")
    if "deathPlace" in predicates:
        birth_info.append(f"died in {predicates['deathPlace'][0]}")
    if "deathDate" in predicates:
        birth_info.append(f"on {predicates['deathDate'][0]}")
    if "deathYear" in predicates:
        birth_info.append(f"in {predicates['deathYear'][0]}")
    if "nationality" in predicates:
        birth_info.append(f"of {predicates['nationality'][0]}")

    if birth_info:
        if len(birth_info) == 1:
            parts.append(f"{main_subject} was {birth_info[0]}")
        else:
            parts.append(f"{main_subject} was {', '.join(birth_info[:-1])} and {birth_info[-1]}")

    # Career information
    career_info = []
    if "office" in predicates:
        career_info.append(f"held the office of {predicates['office'][0]}")
    if "party" in predicates:
        career_info.append(f"belonged to the {predicates['party'][0]} party")
    if "profession" in predicates:
        career_info.append(f"was a {predicates['profession'][0]}")
    if "militaryBranch" in predicates:
        career_info.append(f"served in the {predicates['militaryBranch'][0]}")
    if "militaryRank" in predicates:
        career_info.append(f"with the rank of {predicates['militaryRank'][0]}")

    if career_info:
        if len(career_info) == 1:
            parts.append(career_info[0])
        else:
            parts.append(f"who {', '.join(career_info[:-1])} and {career_info[-1]}")

    # Relationships
    relationships = []
    if "spouse" in predicates:
        relationships.append(f"married to {predicates['spouse'][0]}")
    if "predecessor" in predicates:
        relationships.append(f"preceded by {predicates['predecessor'][0]}")
    if "successor" in predicates:
        relationships.append(f"succeeded by {predicates['successor'][0]}")
    if "hasDeputy" in predicates:
        relationships.append(f"with {predicates['hasDeputy'][0]} as deputy")

    if relationships:
        parts.append(f"with {', '.join(relationships)}")

    # Country/geography info
    if "country" in predicates:
        parts.append(f"in {predicates['country'][0]}")
    if "state" in predicates:
        parts.append(f"from {predicates['state'][0]}")
    if "region" in predicates:
        parts.append(f"in the {predicates['region'][0]} region")

    # Join all parts into a complex sentence
    if len(parts) == 1:
        return parts[0]
    elif len(parts) == 2:
        return f"{parts[0]}, {parts[1]}"
    else:
        return f"{parts[0]}, {', '.join(parts[1:-1])}, and {parts[-1]}"

# EVOLVE-BLOCK-END
